package com.example.bankingapp.data;

import com.example.bankingapp.data.model.Account;
import com.example.bankingapp.data.model.Transaction;
import com.example.bankingapp.data.model.TransactionType;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingRepository {

    private Account currentAccount;
    private final List<Transaction> transactionHistory = new ArrayList<>();
    private final ExecutorService executorService = Executors.newSingleThreadExecutor(); // For simulating async operations

    public BankingRepository() {
        // Initialize with a dummy account for demonstration
        currentAccount = new Account("ACC001", new BigDecimal("1000.00"));
    }

    public Account getAccount() {
        return currentAccount;
    }

    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory); // Return a copy
    }

    // Callback interface for transaction results
    public interface TransactionCallback {
        void onTransactionComplete(Transaction transaction, String message);
        void onTransactionFailed(Transaction transaction, String errorMessage);
    }

    public void processTransaction(TransactionType type, BigDecimal amount, TransactionCallback callback) {
        executorService.execute(() -> {
            Transaction transaction = new Transaction(currentAccount.getAccountId(), type, amount);
            transactionHistory.add(transaction);

            // Simulate network/processing delay
            try {
                Thread.sleep(1500); // 1.5 second delay
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                transaction.setStatus("FAILED");
                callback.onTransactionFailed(transaction, "Transaction interrupted.");
                return;
            }

            BigDecimal currentBalance = currentAccount.getBalance();
            BigDecimal newBalance;
            boolean success = false;
            String message = "";

            switch (type) {
                case DEPOSIT:
                    newBalance = currentBalance.add(amount);
                    currentAccount.setBalance(newBalance);
                    success = true;
                    message = "Deposit successful.";
                    break;
                case WITHDRAWAL:
                    if (currentBalance.compareTo(amount) >= 0) {
                        newBalance = currentBalance.subtract(amount);
                        currentAccount.setBalance(newBalance);
                        success = true;
                        message = "Withdrawal successful.";
                    } else {
                        success = false;
                        message = "Insufficient funds.";
                    }
                    break;
                case TRANSFER:
                    // For simplicity, transfer logic isn't fully implemented (e.g., to another account)
                    // We'll treat it like a withdrawal for now, but mark it as a transfer type.
                    if (currentBalance.compareTo(amount) >= 0) {
                        newBalance = currentBalance.subtract(amount);
                        currentAccount.setBalance(newBalance);
                        success = true;
                        message = "Transfer successful.";
                    } else {
                        success = false;
                        message = "Insufficient funds for transfer.";
                    }
                    break;
            }

            if (success) {
                transaction.setStatus("COMPLETED");
                callback.onTransactionComplete(transaction, message);
            } else {
                transaction.setStatus("FAILED");
                callback.onTransactionFailed(transaction, message);
            }
        });
    }

    public void shutdown() {
        executorService.shutdown();
    }
}
package com.example.bankingapp.viewmodel;

import android.app.Application;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import com.example.bankingapp.data.BankingRepository;
import com.example.bankingapp.data.model.Account;
import com.example.bankingapp.data.model.Transaction;
import com.example.bankingapp.data.model.TransactionType;

import java.math.BigDecimal;

public class BankingViewModel extends AndroidViewModel {

    private final BankingRepository bankingRepository;
    private final MutableLiveData<BigDecimal> accountBalance = new MutableLiveData<>();
    private final MutableLiveData<String> transactionMessage = new MutableLiveData<>();

    public BankingViewModel(@NonNull Application application) {
        super(application);
        bankingRepository = new BankingRepository();
        // Initialize balance
        accountBalance.setValue(bankingRepository.getAccount().getBalance());
    }

    public LiveData<BigDecimal> getAccountBalance() {
        return accountBalance;
    }

    public LiveData<String> getTransactionMessage() {
        return transactionMessage;
    }

    public void performTransaction(TransactionType type, BigDecimal amount) {
        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
            transactionMessage.postValue("Invalid amount entered.");
            return;
        }

        transactionMessage.postValue("Processing " + type.name().toLowerCase() + "...");

        bankingRepository.processTransaction(type, amount, new BankingRepository.TransactionCallback() {
            @Override
            public void onTransactionComplete(Transaction transaction, String message) {
                // Update UI on the main thread
                accountBalance.postValue(bankingRepository.getAccount().getBalance());
                transactionMessage.postValue(message);
            }

            @Override
            public void onTransactionFailed(Transaction transaction, String errorMessage) {
                // Update UI on the main thread
                transactionMessage.postValue(errorMessage);
            }
        });
    }

    @Override
    protected void onCleared() {
        super.onCleared();
        bankingRepository.shutdown(); // Clean up executor service
    }
}
