package com.example.bankingapp.ui;

import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import com.example.bankingapp.R;
import com.example.bankingapp.data.model.TransactionType;
import com.example.bankingapp.viewmodel.BankingViewModel;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.util.Locale;

public class BankingActivity extends AppCompatActivity {

    private BankingViewModel bankingViewModel;

    private TextView balanceAmountTextView;
    private EditText amountEditText;
    private TextView transactionMessageTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        balanceAmountTextView = findViewById(R.id.textView_balanceAmount);
        amountEditText = findViewById(R.id.editText_amount);
        transactionMessageTextView = findViewById(R.id.textView_transactionMessage);
        Button depositButton = findViewById(R.id.button_deposit);
        Button withdrawButton = findViewById(R.id.button_withdraw);
        Button transferButton = findViewById(R.id.button_transfer);

        bankingViewModel = new ViewModelProvider(this).get(BankingViewModel.class);

        // Observe account balance changes
        bankingViewModel.getAccountBalance().observe(this, balance -> {
            NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.US);
            balanceAmountTextView.setText(currencyFormat.format(balance));
        });

        // Observe transaction messages
        bankingViewModel.getTransactionMessage().observe(this, message -> {
            transactionMessageTextView.setText(message);
            if (!TextUtils.isEmpty(message) && message.contains("success")) {
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
                amountEditText.setText(""); // Clear amount field on success
            } else if (!TextUtils.isEmpty(message) && message.contains("failed") || message.contains("Invalid")) {
                 Toast.makeText(this, message, Toast.LENGTH_LONG).show();
            }
        });

        depositButton.setOnClickListener(v -> {
            BigDecimal amount = getAmountFromInput();
            if (amount != null) {
                bankingViewModel.performTransaction(TransactionType.DEPOSIT, amount);
            } else {
                Toast.makeText(this, "Please enter a valid amount.", Toast.LENGTH_SHORT).show();
            }
        });

        withdrawButton.setOnClickListener(v -> {
            BigDecimal amount = getAmountFromInput();
            if (amount != null) {
                bankingViewModel.performTransaction(TransactionType.WITHDRAWAL, amount);
            } else {
                Toast.makeText(this, "Please enter a valid amount.", Toast.LENGTH_SHORT).show();
            }
        });

        transferButton.setOnClickListener(v -> {
            BigDecimal amount = getAmountFromInput();
            if (amount != null) {
                // For simplicity, transfer is treated as a withdrawal from the current account
                // In a real app, this would involve selecting a recipient account.
                bankingViewModel.performTransaction(TransactionType.TRANSFER, amount);
            } else {
                Toast.makeText(this, "Please enter a valid amount.", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private BigDecimal getAmountFromInput() {
        String amountString = amountEditText.getText().toString();
        if (TextUtils.isEmpty(amountString)) {
            return null;
        }
        try {
            return new BigDecimal(amountString);
        } catch (NumberFormatException e) {
            return null;
        }
    }
}